import asyncio
import aiohttp
import json

async def fetch(session, url):
    try:
        async with session.get(url) as response:
            result = {"url": url, "status": response.status}
            if response.status == 200:
                try:
                    result["data"] = await response.json()
                except aiohttp.ContentTypeError:
                    result["data"] = await response.text()
                except json.JSONDecodeError:
                    result["data"] = await response.text()
            else:
                result["error"] = await response.text()
            return result
    except aiohttp.ClientError as e:
        return {"url": url, "error": f"Client error: {e}"}
    except asyncio.TimeoutError:
        return {"url": url, "error": "Request timed out"}
    except Exception as e:
        return {"url": url, "error": f"Unexpected error: {e.__class__.__name__} - {e}"}

async def send_parallel_requests(urls: list[str]) -> list[dict]:
    async with aiohttp.ClientSession() as session:
        tasks = [fetch(session, url) for url in urls]
        results = await asyncio.gather(*tasks)
        return results

if __name__ == "__main__":
    example_endpoints = [
        "https://jsonplaceholder.typicode.com/posts/1",
        "https://jsonplaceholder.typicode.com/users/1",
        "https://api.github.com/users/octocat",
        "http://httpbin.org/status/500",
        "http://invalid.url.example.com",
        "https://jsonplaceholder.typicode.com/posts/2",
        "https://www.google.com"
    ]

    responses = asyncio.run(send_parallel_requests(example_endpoints))

    for res in responses:
        print(json.dumps(res, indent=2, ensure_ascii=False))
